<?php $firstAvailable=null;foreach($variants as $variant)if((int)$variant['stock_qty']>0){$firstAvailable=$variant;break;}?><section class="detail"><div class="gallery"><div class="gallery-main"><?php if($images):foreach($images as $i=>$img):?><img id="image-<?=$i?>" src="<?=url('/media/'.$img['image_path'])?>" alt="<?=$i===0?e($product['name']):''?>"><?php endforeach;else:?><span><?=e(substr($product['name'],0,1))?></span><?php endif?></div><?php if(count($images)>1):?><nav class="gallery-dots" aria-label="Galeri <?=e($product['name'])?>"><?php foreach($images as $i=>$img):?><a href="#image-<?=$i?>" aria-label="Lihat gambar <?=$i+1?> dari <?=count($images)?>"><?=$i+1?></a><?php endforeach?></nav><?php endif?></div><div class="detail-copy"><a class="eyebrow" href="<?=url('/kategori/'.($product['category_slug']??''))?>"><?=e($product['category_name']??'Koleksi')?></a><h1><?=e($product['name'])?></h1><p class="lead"><?=e($product['short_description'])?></p><form method="post" action="<?=url('/keranjang/tambah')?>" class="buy-box"><?=csrf_field()?><input type="hidden" name="return_to" value="<?=e($_SERVER['REQUEST_URI'])?>"><label>Pilih varian<select name="variant_id" id="variant" onchange="updateVariant()" required><?php foreach($variants as $v):?><option value="<?=$v['id']?>" data-price="<?=money($v['pricing']['final'])?>" data-stock="<?=$v['stock_qty']?>" <?=((int)$v['stock_qty']<=0)?'disabled':''?> <?=($firstAvailable&&$firstAvailable['id']===$v['id'])?'selected':''?>><?=e($v['name'])?> · <?=money($v['pricing']['final'])?><?=((int)$v['stock_qty']<=0)?' — Habis':''?></option><?php endforeach?></select></label><div class="buy-line"><strong id="live-price"><?=money($firstAvailable['pricing']['final']??0)?></strong><span id="live-stock"><?=$firstAvailable?'Tersedia '.$firstAvailable['stock_qty']:'Stok habis'?></span></div><label>Jumlah<input id="quantity" type="number" name="quantity" min="1" max="<?=$firstAvailable['stock_qty']??0?>" value="<?=$firstAvailable?1:0?>" <?=$firstAvailable?'':'disabled'?>></label><button id="add-cart" class="button button-large" <?=$firstAvailable?'':'disabled'?>><?=$firstAvailable?'Masukkan keranjang':'Stok habis'?></button></form><div class="prose"><?=nl2br(e($product['description']))?></div></div></section><script>function updateVariant(){const o=document.querySelector('#variant').selectedOptions[0],q=document.querySelector('#quantity'),b=document.querySelector('#add-cart'),stock=Number(o?.dataset.stock||0);document.querySelector('#live-price').textContent=o?.dataset.price||'';document.querySelector('#live-stock').textContent=stock>0?`Tersedia ${stock}`:'Stok habis';q.max=stock;q.disabled=stock<1;q.value=stock<1?0:Math.min(Math.max(Number(q.value),1),stock);b.disabled=stock<1;b.textContent=stock>0?'Masukkan keranjang':'Stok habis'}</script>
